<?php require '_header.php'; $items=read_json('skills'); if($_SERVER['REQUEST_METHOD']==='POST'){ verify_csrf(); $new=[]; foreach($_POST['title'] as $i=>$title){ if(trim($title)==='') continue; $current=$_POST['current_image'][$i] ?? 'assets/svg/skill-web.svg'; $image=upload_image('image_'.$i,$current); $new[]=['title'=>trim($title),'summary'=>trim($_POST['summary'][$i]??''),'image'=>$image]; } write_json('skills',$new); header('Location: skills.php'); exit; } ?><h1>Skills</h1><p>Edit skill text and visuals shown on the homepage.</p><form method="post" enctype="multipart/form-data" class="admin-form"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><?php foreach($items as $i=>$s): ?><div class="admin-group"><label>Title<input name="title[]" value="<?=e($s['title'])?>"></label><input type="hidden" name="current_image[]" value="<?=e($s['image'])?>"><label>Current Image<?php if(!empty($s['image'])): ?><img class="admin-preview" src="../<?=e($s['image'])?>" alt=""><?php endif; ?><input type="file" name="image_<?=$i?>" accept="image/*"></label><label>Summary<textarea name="summary[]"><?=e($s['summary'])?></textarea></label></div><?php endforeach; ?><div class="admin-group"><label>Title<input name="title[]"></label><input type="hidden" name="current_image[]" value="assets/svg/skill-web.svg"><label>Image<input type="file" name="image_<?=count($items)?>" accept="image/*"></label><label>Summary<textarea name="summary[]"></textarea></label></div><button class="btn primary">Save Skills</button></form><?php require '_footer.php'; ?>